"""Diagnose exactly why JS extraction fails on search results page.

Connects to Chrome, navigates to search, waits for results,
then runs detailed analysis of DOM structure to understand
why the extraction JS can't find candidates.
"""

import asyncio
import json
import sys
from urllib.parse import urlencode

sys.path.insert(0, '.')

from patchright.async_api import async_playwright


CDP_URL = "http://localhost:9222"
SEARCH_CENTER_URL = "https://maimai.cn/web/search_center"
KEYWORD = "安卓"


async def main():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp(CDP_URL)
        context = browser.contexts[0]
        page = context.pages[0] if context.pages else await context.new_page()

        # Navigate to search
        params = {'type': 'contact', 'query': KEYWORD, 'highlight': 'true'}
        url = f"{SEARCH_CENTER_URL}?{urlencode(params)}"
        print(f"Navigating to: {url}")
        await page.goto(url, wait_until='domcontentloaded')

        # Wait for results to actually load (up to 15s)
        print("Waiting for results to load...")
        try:
            await page.wait_for_function(
                '''() => {
                    const body = document.body ? document.body.innerText : '';
                    if (body.includes('搜索数据中') || body.includes('加载中')) return false;
                    return true;
                }''',
                timeout=15000,
            )
            print("Loading text disappeared!")
        except Exception as e:
            print(f"Timeout waiting for load: {e}")

        # Extra wait for rendering
        await page.wait_for_timeout(3000)

        # Click 人脉 tab
        renmai_tab = await page.query_selector('text="人脉"')
        if renmai_tab:
            await renmai_tab.click()
            print("Clicked 人脉 tab")
            await page.wait_for_timeout(3000)
        else:
            print("人脉 tab not found!")

        # Take screenshot for reference
        await page.screenshot(path="data/screenshots/diag_before_extract.png", full_page=False)
        print("Screenshot saved: data/screenshots/diag_before_extract.png")

        # === DETAILED DOM ANALYSIS ===
        print("\n=== DOM Analysis ===")
        analysis = await page.evaluate('''() => {
            const results = {
                total_imgs: 0,
                avatar_sized_imgs: [],
                all_img_sizes: [],
                card_attempts: [],
                text_parts_samples: [],
            };

            const images = document.querySelectorAll('img');
            results.total_imgs = images.length;

            for (const img of images) {
                const rect = img.getBoundingClientRect();
                const size = { w: Math.round(rect.width), h: Math.round(rect.height), src: (img.src || '').substring(0, 80) };
                results.all_img_sizes.push(size);

                // Check avatar criteria
                if (rect.width >= 20 && rect.width <= 100 &&
                    rect.height >= 20 && rect.height <= 100) {
                    results.avatar_sized_imgs.push(size);

                    // Try to find card parent (same logic as extraction code)
                    let card = img.parentElement;
                    let cardFound = false;
                    let traversal = [];
                    for (let i = 0; i < 8 && card; i++) {
                        const cardRect = card.getBoundingClientRect();
                        traversal.push({
                            tag: card.tagName,
                            id: (card.id || '').substring(0, 30),
                            cls: (card.className || '').substring(0, 50),
                            w: Math.round(cardRect.width),
                            h: Math.round(cardRect.height),
                        });
                        if (cardRect.width > 200 && cardRect.height > 50 && cardRect.height < 200) {
                            cardFound = true;
                            break;
                        }
                        card = card.parentElement;
                    }

                    if (cardFound && card) {
                        // Get text parts from card
                        const textParts = [];
                        const walker = document.createTreeWalker(card, NodeFilter.SHOW_TEXT, null, false);
                        while (walker.nextNode()) {
                            const text = walker.currentNode.textContent.trim();
                            if (text && text.length > 0 && text.length < 100) {
                                textParts.push(text);
                            }
                        }
                        results.card_attempts.push({
                            cardFound: true,
                            traversal: traversal,
                            textParts: textParts,
                            cardTag: card.tagName,
                            cardId: card.id || '',
                            cardClass: (card.className || '').substring(0, 80),
                        });
                    } else {
                        results.card_attempts.push({
                            cardFound: false,
                            traversal: traversal,
                            reason: card ? 'no matching size' : 'ran out of parents',
                        });
                    }
                }
            }

            // Also check for non-img avatars (CSS background, SVG, etc.)
            results.css_bg_avatars = 0;
            const allDivs = document.querySelectorAll('div, span');
            for (const el of allDivs) {
                const style = window.getComputedStyle(el);
                const bg = style.backgroundImage || '';
                if (bg && bg !== 'none' && bg.includes('url(')) {
                    const rect = el.getBoundingClientRect();
                    if (rect.width >= 20 && rect.width <= 100 &&
                        rect.height >= 20 && rect.height <= 100) {
                        results.css_bg_avatars++;
                    }
                }
            }

            // Check for member_entry and contactcard IDs
            results.member_entries = document.querySelectorAll('[id^="member_entry_"]').length;
            results.contactcards = document.querySelectorAll('[id^="contactcard_"]').length;

            // Check for profile links
            results.profile_links = document.querySelectorAll(
                'a[href*="/contact/"], a[href*="/u/"], a[href*="egid="], a[href*="profile"]'
            ).length;

            // Dump some profile link hrefs for reference
            results.sample_links = [];
            const links = document.querySelectorAll('a[href*="/contact/"], a[href*="/u/"]');
            for (let i = 0; i < Math.min(5, links.length); i++) {
                results.sample_links.push({
                    href: links[i].getAttribute('href'),
                    text: (links[i].innerText || '').substring(0, 30),
                });
            }

            return results;
        }''')

        print(f"\nTotal <img> elements: {analysis['total_imgs']}")
        print(f"Avatar-sized imgs (20-100px): {len(analysis['avatar_sized_imgs'])}")
        print(f"CSS background avatars: {analysis['css_bg_avatars']}")
        print(f"member_entry_ IDs: {analysis['member_entries']}")
        print(f"contactcard_ IDs: {analysis['contactcards']}")
        print(f"Profile links: {analysis['profile_links']}")

        print(f"\nAll image sizes:")
        for img in analysis['all_img_sizes']:
            print(f"  {img['w']}x{img['h']} — {img['src']}")

        print(f"\nAvatar-sized images:")
        for img in analysis['avatar_sized_imgs']:
            print(f"  {img['w']}x{img['h']} — {img['src']}")

        print(f"\nCard attempts ({len(analysis['card_attempts'])}):")
        for i, attempt in enumerate(analysis['card_attempts']):
            print(f"\n  [{i}] cardFound={attempt['cardFound']}")
            if attempt['cardFound']:
                print(f"      tag={attempt['cardTag']}, id={attempt.get('cardId','')}, class={attempt.get('cardClass','')}")
                print(f"      textParts ({len(attempt['textParts'])}): {attempt['textParts'][:10]}")
            else:
                print(f"      reason={attempt.get('reason','')}")
            print(f"      traversal:")
            for step in attempt['traversal']:
                print(f"        {step['tag']} id='{step['id']}' w={step['w']} h={step['h']}")

        print(f"\nSample profile links:")
        for link in analysis.get('sample_links', []):
            print(f"  {link['text']} -> {link['href']}")

        print("\n=== Done ===")


if __name__ == '__main__':
    asyncio.run(main())

