                        }
                        card = card.parentElement;
                    }

                    if (cardFound && card) {
                        // Get text parts from card
                        const textParts = [];
                        const walker = document.createTreeWalker(card, NodeFilter.SHOW_TEXT, null, false);
                        while (walker.nextNode()) {
                            const text = walker.currentNode.textContent.trim();
                            if (text && text.length > 0 && text.length < 100) {
                                textParts.push(text);
                            }
                        }
                        results.card_attempts.push({
                            cardFound: true,
                            traversal: traversal,
                            textParts: textParts,
                            cardTag: card.tagName,
                            cardId: card.id || '',
                            cardClass: (card.className || '').substring(0, 80),
                        });
                    } else {
                        results.card_attempts.push({
                            cardFound: false,
                            traversal: traversal,
                            reason: card ? 'no matching size' : 'ran out of parents',
                        });
                    }
                }
            }

            // Also check for non-img avatars (CSS background, SVG, etc.)
            results.css_bg_avatars = 0;
            const allDivs = document.querySelectorAll('div, span');
            for (const el of allDivs) {
                const style = window.getComputedStyle(el);
                const bg = style.backgroundImage || '';
