                    const rect = el.getBoundingClientRect();
                    if (rect.width >= 20 && rect.width <= 100 &&
                        rect.height >= 20 && rect.height <= 100) {
                        results.css_bg_avatars++;
                    }
                }
            }

            // Check for member_entry and contactcard IDs
            results.member_entries = document.querySelectorAll('[id^="member_entry_"]').length;
            results.contactcards = document.querySelectorAll('[id^="contactcard_"]').length;

            // Check for profile links
            results.profile_links = document.querySelectorAll(
                'a[href*="/contact/"], a[href*="/u/"], a[href*="egid="], a[href*="profile"]'
            ).length;

            // Dump some profile link hrefs for reference
            results.sample_links = [];
            const links = document.querySelectorAll('a[href*="/contact/"], a[href*="/u/"]');
            for (let i = 0; i < Math.min(5, links.length); i++) {
                results.sample_links.push({
                    href: links[i].getAttribute('href'),
                    text: (links[i].innerText || '').substring(0, 30),
                });
            }

            return results;
        }''')

        print(f"\nTotal <img> elements: {analysis['total_imgs']}")
        print(f"Avatar-sized imgs (20-100px): {len(analysis['avatar_sized_imgs'])}")
        print(f"CSS background avatars: {analysis['css_bg_avatars']}")
        print(f"member_entry_ IDs: {analysis['member_entries']}")
        print(f"contactcard_ IDs: {analysis['contactcards']}")
        print(f"Profile links: {analysis['profile_links']}")

        print(f"\nAll image sizes:")
        for img in analysis['all_img_sizes']:
            print(f"  {img['w']}x{img['h']} — {img['src']}")

        print(f"\nAvatar-sized images:")
        for img in analysis['avatar_sized_imgs']:
            print(f"  {img['w']}x{img['h']} — {img['src']}")

        print(f"\nCard attempts ({len(analysis['card_attempts'])}):")
        for i, attempt in enumerate(analysis['card_attempts']):
            print(f"\n  [{i}] cardFound={attempt['cardFound']}")
            if attempt['cardFound']:
                print(f"      tag={attempt['cardTag']}, id={attempt.get('cardId','')}, class={attempt.get('cardClass','')}")
                print(f"      textParts ({len(attempt['textParts'])}): {attempt['textParts'][:10]}")
            else:
                print(f"      reason={attempt.get('reason','')}")
            print(f"      traversal:")
            for step in attempt['traversal']:
                print(f"        {step['tag']} id='{step['id']}' w={step['w']} h={step['h']}")

        print(f"\nSample profile links:")
        for link in analysis.get('sample_links', []):
            print(f"  {link['text']} -> {link['href']}")

        print("\n=== Done ===")


if __name__ == '__main__':
    asyncio.run(main())

