"""

import asyncio
import json
import sys
from urllib.parse import urlencode

sys.path.insert(0, '.')

from patchright.async_api import async_playwright


CDP_URL = "http://localhost:9222"
SEARCH_CENTER_URL = "https://maimai.cn/web/search_center"
KEYWORD = "安卓"


async def main():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp(CDP_URL)
        context = browser.contexts[0]
        page = context.pages[0] if context.pages else await context.new_page()

        # Navigate and wait for results
        params = {'type': 'contact', 'query': KEYWORD, 'highlight': 'true'}
        url = f"{SEARCH_CENTER_URL}?{urlencode(params)}"
        await page.goto(url, wait_until='domcontentloaded')

        try:
            await page.wait_for_function(
                '''() => {
                    const body = document.body ? document.body.innerText : '';
                    return !body.includes('搜索数据中') && !body.includes('加载中');
                }''',
                timeout=15000,
            )
        except Exception:
            pass

        await page.wait_for_timeout(3000)

        # Click 人脉 tab
        renmai_tab = await page.query_selector('text="人脉"')
        if renmai_tab:
            await renmai_tab.click()
            await page.wait_for_timeout(3000)

        # Analyze CSS background avatar elements
        print("=== CSS Background Avatar Elements ===")
        avatar_analysis = await page.evaluate('''() => {
            const avatars = [];
            const allEls = document.querySelectorAll('*');

            for (const el of allEls) {
                const style = window.getComputedStyle(el);
                const bg = style.backgroundImage || '';
                if (!bg || bg === 'none' || !bg.includes('url(')) continue;

                const rect = el.getBoundingClientRect();
                if (rect.width < 20 || rect.width > 100 || rect.height < 20 || rect.height > 100) continue;
                // Skip if not visible
                if (rect.top < 0 || rect.left < 0) continue;

                // This looks like an avatar — analyze its context
                const avatar = {
                    tag: el.tagName,
                    className: (el.className || '').substring(0, 100),
                    size: Math.round(rect.width) + 'x' + Math.round(rect.height),
                    bgUrl: bg.substring(0, 120),
                };

                // Find card parent by traversing up
                let card = el.parentElement;
                let depth = 0;
                let ancestry = [];
                for (let i = 0; i < 15 && card; i++) {
                    const cardRect = card.getBoundingClientRect();
                    ancestry.push({
                        tag: card.tagName,
                        id: (card.id || '').substring(0, 40),
                        cls: (card.className || '').substring(0, 60),
                        w: Math.round(cardRect.width),
                        h: Math.round(cardRect.height),
                    });
                    card = card.parentElement;
                    depth++;
                }
                avatar.ancestry = ancestry;

                // Get text from reasonable card-like parent
                // Try different ancestor levels to find the result card
                card = el.parentElement;
                for (let i = 0; i < 10 && card; i++) {
                    const cr = card.getBoundingClientRect();
                    // A result card is typically 400-900px wide, 60-300px tall
                    if (cr.width > 300 && cr.height > 60 && cr.height < 300) {
                        const textParts = [];
                        const walker = document.createTreeWalker(card, NodeFilter.SHOW_TEXT, null, false);
                        while (walker.nextNode()) {
                            const text = walker.currentNode.textContent.trim();
                            if (text && text.length > 0 && text.length < 100) {
                                textParts.push(text);
                            }
                        }
                        avatar.cardText = textParts;
                        avatar.cardLevel = i;
                        avatar.cardSize = Math.round(cr.width) + 'x' + Math.round(cr.height);
                        avatar.cardTag = card.tagName;
                        avatar.cardClass = (card.className || '').substring(0, 80);

                        // Check for links inside this card
                        const links = card.querySelectorAll('a[href]');
                        avatar.links = [];
                        for (const link of links) {
                            const href = link.getAttribute('href') || '';
                            if (href.includes('/contact') || href.includes('/u/') ||
                                href.includes('dstu=') || href.includes('egid=')) {
                                avatar.links.push({
                                    href: href.substring(0, 100),
                                    text: (link.innerText || '').substring(0, 30),
                                });
                            }
                        }

                        // Check for IDs in this card
                        const idsInCard = card.querySelectorAll('[id]');
                        avatar.idsInCard = [];
                        for (const idEl of idsInCard) {
                            if (idEl.id) avatar.idsInCard.push(idEl.id.substring(0, 50));
                        }

                        break;
                    }
                    card = card.parentElement;
                }

                avatars.push(avatar);
            }

            return avatars;
        }''')

        print(f"\nFound {len(avatar_analysis)} CSS background avatars:")
        for i, av in enumerate(avatar_analysis):
            print(f"\n--- Avatar [{i}] ---")
            print(f"  Element: <{av['tag']}> class='{av['className']}' size={av['size']}")
            print(f"  BG: {av['bgUrl']}")

            if 'cardText' in av:
                print(f"  Card found at level {av['cardLevel']}: <{av['cardTag']}> {av['cardSize']}")
                print(f"  Card class: {av['cardClass']}")
                print(f"  Text parts: {av['cardText']}")
                if av.get('links'):
                    print(f"  Links:")
                    for link in av['links']:
                        print(f"    {link['text']} -> {link['href']}")
                if av.get('idsInCard'):
                    print(f"  IDs in card: {av['idsInCard']}")
            else:
                print("  No card-like parent found!")
                print(f"  Ancestry:")
                for step in av['ancestry'][:5]:
                    print(f"    <{step['tag']}> id='{step['id']}' cls='{step['cls']}' {step['w']}x{step['h']}")

        # Also dump the outerHTML of first few result items
        print("\n\n=== Raw HTML of first result card ===")
        first_card_html = await page.evaluate('''() => {
            const allEls = document.querySelectorAll('*');
            for (const el of allEls) {
                const style = window.getComputedStyle(el);
                const bg = style.backgroundImage || '';
                if (!bg || bg === 'none' || !bg.includes('url(')) continue;
                const rect = el.getBoundingClientRect();
                if (rect.width < 20 || rect.width > 100 || rect.height < 20 || rect.height > 100) continue;
                if (rect.top < 0) continue;

                // Found an avatar, go up to find card
                let card = el.parentElement;
                for (let i = 0; i < 10 && card; i++) {
                    const cr = card.getBoundingClientRect();
                    if (cr.width > 300 && cr.height > 60 && cr.height < 300) {
                        return card.outerHTML.substring(0, 3000);
                    }
                    card = card.parentElement;
                }
            }
            return 'No card found';
        }''')
        print(first_card_html[:3000])

        print("\n=== Done ===")


if __name__ == '__main__':
    asyncio.run(main())

