"""Diagnose actual DOM structure of loaded search results.

Takes a step-by-step approach:
1. Navigate to search page
2. Wait until results visually appear (confirm with screenshot)
3. THEN analyze what DOM elements make up the result cards
"""

import asyncio
import sys
from urllib.parse import urlencode

sys.path.insert(0, '.')
from patchright.async_api import async_playwright

CDP_URL = "http://localhost:9222"
SEARCH_CENTER_URL = "https://maimai.cn/web/search_center"
KEYWORD = "安卓"


async def main():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp(CDP_URL)
        context = browser.contexts[0]
        page = context.pages[0] if context.pages else await context.new_page()

        # Step 1: Navigate
        params = {'type': 'contact', 'query': KEYWORD, 'highlight': 'true'}
        url = f"{SEARCH_CENTER_URL}?{urlencode(params)}"
        print(f"1. Navigating to: {url}")
        await page.goto(url, wait_until='domcontentloaded')

        # Step 2: Wait for results to actually render (long wait)
        print("2. Waiting 8s for initial load...")
        await page.wait_for_timeout(8000)

        # Check state BEFORE clicking tab
        state1 = await page.evaluate('''() => {
            const body = document.body.innerText || '';
            return {
                hasLoading: body.includes('搜索数据中') || body.includes('加载中'),
                hasKeyword: body.includes('安卓'),
                hasHaoYou: body.includes('好友'),
                bodyPreview: body.substring(0, 300),
            };
        }''')
        print(f"   State before tab click: loading={state1['hasLoading']}, keyword={state1['hasKeyword']}, 好友={state1['hasHaoYou']}")
        await page.screenshot(path="data/screenshots/diag_step2_before_tab.png")
        print("   Screenshot: diag_step2_before_tab.png")

        # Step 3: Check which tab is currently active
        tabs = await page.evaluate('''() => {
            const links = document.querySelectorAll('a, span, div');
            const tabs = [];
            for (const el of links) {
                const text = (el.innerText || '').trim();
                if (['实名动态', '职言交流', '人脉'].includes(text)) {
                    const style = window.getComputedStyle(el);
                    tabs.push({
                        text: text,
                        tag: el.tagName,
                        className: (el.className || '').substring(0, 60),
                        color: style.color,
                        fontWeight: style.fontWeight,
                        borderBottom: style.borderBottom,
                    });
                }
            }
            return tabs;
        }''')
        print(f"3. Tabs found: {len(tabs)}")
        for t in tabs:
            print(f"   {t['text']}: color={t['color']}, weight={t['fontWeight']}, class={t['className']}")

        # Step 4: Click 人脉 tab and wait
        renmai = await page.query_selector('text="人脉"')
        if renmai:
            print("4. Clicking 人脉 tab...")
            await renmai.click()
            print("   Waiting 8s for results...")
            await page.wait_for_timeout(8000)

            state2 = await page.evaluate('''() => {
                const body = document.body.innerText || '';
                return {
                    hasLoading: body.includes('搜索数据中') || body.includes('加载中'),
                    hasKeyword: body.includes('安卓'),
                    hasHaoYou: body.includes('好友'),
                    currentUrl: window.location.href,
                };
            }''')
            print(f"   State after 人脉: loading={state2['hasLoading']}, keyword={state2['hasKeyword']}, 好友={state2['hasHaoYou']}")
            print(f"   URL: {state2['currentUrl']}")
            await page.screenshot(path="data/screenshots/diag_step4_after_tab.png")
            print("   Screenshot: diag_step4_after_tab.png")

        # Step 5: Deep DOM analysis of the main content area
        print("\n5. Deep DOM analysis...")
        dom = await page.evaluate('''() => {
            // Find the main content area (not sidebar)
            const mainArea = document.querySelector('.v6Layout__main') ||
                           document.querySelector('.PCcontainer') ||
                           document.querySelector('[class*="content"]') ||
                           document.body;

            const result = {
                mainAreaClass: (mainArea.className || '').substring(0, 80),
                childCount: mainArea.children.length,
            };

            // Get ALL elements in main area with their structure
            // Focus on finding repeated patterns (result cards)
            const allChildren = mainArea.querySelectorAll('*');
            const classCounts = {};
            for (const el of allChildren) {
                const cls = el.className || '';
                if (typeof cls === 'string' && cls.length > 0 && cls.length < 100) {
                    classCounts[cls] = (classCounts[cls] || 0) + 1;
                }
            }

            // Find classes that appear 3+ times (likely result card patterns)
            result.repeatedClasses = {};
            for (const [cls, count] of Object.entries(classCounts)) {
                if (count >= 3 && count <= 30) {
                    // Get sample element info
                    const sample = mainArea.querySelector('.' + CSS.escape(cls.split(' ')[0]));
                    if (sample) {
                        const rect = sample.getBoundingClientRect();
                        result.repeatedClasses[cls] = {
                            count: count,
                            tag: sample.tagName,
                            w: Math.round(rect.width),
                            h: Math.round(rect.height),
                        };
                    }
                }
            }

            // Check for any elements that look like person names
            // (text nodes with 2-4 CJK chars that could be names)
            result.potentialNames = [];
            const walker = document.createTreeWalker(mainArea, NodeFilter.SHOW_TEXT, null, false);
            while (walker.nextNode()) {
                const text = walker.currentNode.textContent.trim();
                if (text.length >= 2 && text.length <= 4 &&
                    /^[\u4e00-\u9fa5]+$/.test(text)) {
                    const parent = walker.currentNode.parentElement;
                    if (parent) {
                        const rect = parent.getBoundingClientRect();
                        if (rect.width > 0 && rect.height > 0 && rect.top > 50) {
                            result.potentialNames.push({
                                text: text,
                                parentTag: parent.tagName,
                                parentClass: (parent.className || '').substring(0, 50),
                                top: Math.round(rect.top),
                            });
                        }
                    }
                }
            }

            // Find all <a> links in the main area
            const links = mainArea.querySelectorAll('a[href]');
            result.allLinks = [];
            for (const link of links) {
                const href = link.getAttribute('href') || '';
                const text = (link.innerText || '').trim();
                if (text.length > 0 && text.length < 30 && href.length > 1) {
                    const rect = link.getBoundingClientRect();
                    if (rect.top > 50) {
                        result.allLinks.push({
                            text: text.substring(0, 20),
                            href: href.substring(0, 80),
                            top: Math.round(rect.top),
                        });
                    }
                }
            }

