            await page.screenshot(path="data/screenshots/diag_input_after_renmai.png")
            print("   Screenshot: diag_input_after_renmai.png")

        # Step 7: Now test the URL approach with type=contact directly
        print("\n7. Test: URL with type=contact (skip to 人脉 results)...")
        # Navigate with type=contact which is supposed to go to 人脉 tab directly
        from urllib.parse import urlencode
        params = {'type': 'contact', 'query': KEYWORD, 'highlight': 'true'}
        url = f"{SEARCH_CENTER_URL}?{urlencode(params)}"
