                url: window.location.href,
                hasKeyword: body.includes('安卓'),
                hasHaoYou: body.includes('好友') || body.includes('关注'),
                hasLoading: body.includes('搜索数据中') || body.includes('加载中'),
            };
        }''')
        print(f"   After 2s: keyword={state3['hasKeyword']}, friends={state3['hasHaoYou']}, loading={state3['hasLoading']}")
        print(f"   URL: {state3['url']}")
        await page.screenshot(path="data/screenshots/diag_url_2s.png")
        print("   Screenshot: diag_url_2s.png")

        # Now check the DOM for avatars/cards at this moment
        dom = await page.evaluate('''() => {
            const imgs = document.querySelectorAll('img');
            let imgCount = 0;
            for (const img of imgs) {
                const rect = img.getBoundingClientRect();
                if (rect.width >= 20 && rect.width <= 100 && rect.height >= 20 && rect.height <= 100) {
                    imgCount++;
                }
            }

            // Check for CSS bg avatars in content area
            let bgAvatars = 0;
            const allEls = document.querySelectorAll('*');
            for (const el of allEls) {
                const style = window.getComputedStyle(el);
                const bg = style.backgroundImage || '';
                if (!bg || bg === 'none' || !bg.includes('url(') || !bg.includes('taou.com')) continue;
                const rect = el.getBoundingClientRect();
                if (rect.width >= 30 && rect.width <= 80 && rect.height >= 30 && rect.height <= 80 && rect.top > 100) {
                    bgAvatars++;
                }
            }

            return {
                avatarImgs: imgCount,
                bgAvatars: bgAvatars,
                memberEntries: document.querySelectorAll('[id^="member_entry_"]').length,
                contactcards: document.querySelectorAll('[id^="contactcard_"]').length,
                profileLinks: document.querySelectorAll('a[href*="/contact/"], a[href*="/u/"]').length,
            };
        }''')
        print(f"   DOM: {dom}")

        print("\n=== Done ===")


if __name__ == '__main__':
    asyncio.run(main())

